const body = $input.first().json;
let extracted = body.extracted;
if (typeof extracted === 'string') {
  try { extracted = JSON.parse(extracted); } catch(e) { extracted = {}; }
}

// Harga per m2 berdasarkan tipe & tier (dalam Rupiah)
const priceTable = {
  'rumah': { 'ekonomi': [3500000,4500000], 'standar': [5000000,6000000], 'menengah': [6500000,8000000], 'premium': [9000000,12000000] },
  'cafe': { 'standar': [5500000,7000000], 'menengah': [7500000,9500000], 'premium': [10000000,14000000] },
  'restoran': { 'standar': [5500000,7000000], 'menengah': [7500000,9500000], 'premium': [10000000,14000000] },
  'kantor': { 'standar': [4500000,6000000], 'menengah': [6500000,8500000], 'premium': [9000000,12000000] },
  'villa': { 'standar': [6000000,8000000], 'menengah': [8500000,11000000], 'premium': [12000000,16000000] },
  'ruko': { 'standar': [4000000,5500000], 'menengah': [6000000,7500000] },
  'renovasi': { 'ringan': [1500000,2500000], 'sedang': [2500000,4000000], 'berat': [4000000,6000000] }
};

// Fee percentage berdasarkan kategori
const feePctTable = {
  'arsitektur': [5, 8], 'interior': [7, 10], 'komersial': [6, 9],
  'lansekap': [5, 7], 'pengawasan': [3, 5]
};

// Auto-map service berdasarkan building type
const autoService = {
  'cafe': 'komersial', 'restoran': 'komersial', 'villa': 'arsitektur',
  'rumah': 'arsitektur', 'kantor': 'arsitektur', 'ruko': 'arsitektur', 'renovasi': 'interior'
};

const rawType = (extracted.building_type || 'rumah').toLowerCase();
const rawTier = (extracted.tier || 'standar').toLowerCase();
const rawService = (extracted.service_type || '').toLowerCase();
const area = extracted.area_sqm || 100;
const areaAssumed = !extracted.area_sqm;

// Cari harga
const typeKey = Object.keys(priceTable).find(k => rawType.includes(k)) || 'rumah';
const tierKey = Object.keys(priceTable[typeKey] || {}).find(k => rawTier.includes(k)) || 'standar';
const prices = (priceTable[typeKey] && priceTable[typeKey][tierKey]) || [5000000, 6000000];

const rabMin = prices[0] * area;
const rabMax = prices[1] * area;
const rabAvg = (rabMin + rabMax) / 2;

// Fee
const serviceKey = rawService || autoService[typeKey] || 'arsitektur';
const feePcts = feePctTable[serviceKey] || [5, 8];
const feeMin = rabAvg * feePcts[0] / 100;
const feeMax = rabAvg * feePcts[1] / 100;
const feeAvg = (feeMin + feeMax) / 2;
const ppn = feeAvg * 0.11;
const totalFee = feeAvg + ppn;

const fmt = (n) => {
  if (n >= 1000000000) return 'Rp ' + (n/1000000000).toFixed(1) + ' M';
  if (n >= 1000000) return 'Rp ' + Math.round(n/1000000) + ' jt';
  return 'Rp ' + n.toLocaleString('id-ID');
};

return [{
  json: {
    from: body.from,
    clientName: body.clientName || 'Pelanggan',
    phoneNumberId: body.phoneNumberId || '1052743247932102',
    area, areaAssumed,
    buildingType: typeKey,
    tier: tierKey,
    serviceCategory: serviceKey,
    rabMin, rabMax, rabAvg,
    rabMinFmt: fmt(rabMin), rabMaxFmt: fmt(rabMax), rabAvgFmt: fmt(rabAvg),
    feePctMin: feePcts[0], feePctMax: feePcts[1],
    feeMin, feeMax, feeAvg,
    feeMinFmt: fmt(feeMin), feeMaxFmt: fmt(feeMax), feeAvgFmt: fmt(feeAvg),
    ppn, ppnFmt: fmt(ppn),
    totalFee, totalFeeFmt: fmt(totalFee)
  }
}];

const d = $json;
const name = (d.clientName || 'kak').split(' ')[0];
const areaNote = d.areaAssumed ? '
(estimasi berdasarkan luas 100m2, sesuaikan kalau beda ya)' : '';
const feeRange = d.feePctMin !== d.feePctMax ? d.feePctMin + '-' + d.feePctMax + '%' : d.feePctMin + '%';
const feeDisplay = d.feePctMin !== d.feePctMax ? d.feeMinFmt + ' - ' + d.feeMaxFmt : d.feeAvgFmt;

const replyText = `Halo ${name}, ini estimasi dari Syifa ya.

Proyek: ${d.buildingType} (${d.tier})
Luas: ${d.area}m2${areaNote}

Estimasi RAB Konstruksi:
${d.rabMinFmt} - ${d.rabMaxFmt}
(rata-rata ${d.rabAvgFmt})

Fee Jasa Desain Sudut Ruang (${feeRange} dari RAB):
${feeDisplay}

PPN 11%: ${d.ppnFmt}
Total Fee Jasa: ${d.totalFeeFmt}

Ini masih estimasi awal ya, bisa berubah setelah survey dan diskusi detail.

Mau kita buatkan proposal lengkap?`;

return [{ json: { ...d, replyText } }];
